rule-html-harness.pageList:
{% for section in sections %}

  {{ section.name }}
  {{ section.label | default(section.name) }}

    {% for field in section.fields | default([]) %}

      {{ field.name }}
      {{ field.label | default(field.name) }}
      {{ field.field_type | default('Text') }}
      {{ field.property_ref | default(field.name) }}
      {{ field.required | default('false') }}
      {{ field.read_only | default('false') }}
      {% if field.field_type == "Dropdown" %}
      {{ field.data_page | default('') }}
      {% endif %}
      {% if field.visibility_condition %}
      {{ field.visibility_condition }}
      {% endif %}

    {% endfor %}


{% endfor %}

{% for action in actions | default([]) %}

  {{ action.label }}
  {{ action.type | default('FlowAction') }}
  {{ action.target | default('') }}

{% endfor %}
